  ('aboriginal-c5fb3965-moex-00330', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '下列何者為財產上法律行為，有完全行為能力？', '["年滿20歲，經監護宣告者", "年滿18歲，得購買菸酒者", "年滿18歲，結婚無效者", "年滿18歲，結婚後卻又離婚者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00331', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '下列有關民法規定法律行為之敘述，何者正確？', '["法律行為，違反原住民之習慣或外籍配偶之本國風俗者，無效", "法律行為係乘20歲以上之成年人，於輕率或無經驗之情形下，使其為不動產之塗銷登記者，無效", "法律行為，不依法定方式者，無效。但法律另有規定者，不在此限", "法律行為係乘70歲以上之成年人，於急迫之情形下，使其為動產之移轉占有，且依當時情形顯違 反一般交易習慣者，法院應依檢察官之聲請，撤銷其法律行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00332', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '下列關於普通地上權之敘述，何者正確？', '["地上權設定後，因土地價值之昇降，依原定地租給付顯失公平者，當事人得請求法院增減之", "地上權設定後，地上權人如因不可抗力，妨礙其土地之使用，仍得請求免除或減少租金", "地上權因地上建築物或其他工作物之滅失而消滅", "地上權未定有期限，而有支付地租之約定者，地上權人得支付未到期之三年分地租後，拋棄其權利"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00333', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '關於分管契約於第三人之效力，下列敘述何者錯誤？', '["於共有之不動產，以分管契約經登記者為限，其效力及於應有部分之受讓人", "於區分所有建物，其分管契約之效力及於惡意之應有部分受讓人", "於共有之動產，其分管契約之效力及於惡意之應有部分受讓人", "於已登記之共有不動產，其分管契約非經登記，不得對抗應有部分之受讓人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00334', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '關於合會中，會首之權利及義務，下列敘述何者錯誤？', '["主持標會及通知會員開會", "首期合會金不經投標，由會首取得", "無人出標時，原則上由會首決定何人得標", "代墊會款之義務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
