  ('aboriginal-c5fb3965-moex-00336', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '下列關於民法規定輔助宣告之敘述，何者正確？', '["法院應優先選定受輔助宣告人之配偶擔任輔助人", "受輔助宣告人之財產，由輔助人管理", "輔助開始時，輔助人應於二個月內開具財產清冊，並陳報法院", "輔助人得請求報酬，其數額由法院按其勞力及受監護人之資力酌定之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00337', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '下列何種婚姻關係得撤銷？', '["結婚之證人並未親見親聞雙方當事人有結婚之真意", "婚姻之一方當事人年僅15歲", "四親等旁系血親之表姊與表弟間之婚姻", "有婚姻者，再與第三人結婚"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:06+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL)
